const shapeSortConfig = {
  tileSizePx: 72,
  dragPaddingPx: 6,
  snapTolerancePx: 16,
};

window.shapeSortConfig = shapeSortConfig;

function canGrabTile(pointer, tileRect) {
  const padding = shapeSortConfig.dragPaddingPx;
  return (
    pointer.x >= tileRect.left - padding &&
    pointer.x <= tileRect.right + padding &&
    pointer.y >= tileRect.top - padding &&
    pointer.y <= tileRect.bottom + padding
  );
}

window.canGrabShapeSortTile = canGrabTile;

.shape-sort-board {
  min-height: 360px;
  padding: 16px;
}

.shape-tile {
  width: 72px;
  height: 72px;
  border-radius: 18px;
}

window.inputHelpers = {
  pointerSlopPx: 8,
  normalizePointer(point) {
    return {
      x: point.clientX,
      y: point.clientY,
    };
  },
};

window.color_matchConfig = {
  ready: true,
};

window.letter_bubblesConfig = {
  ready: true,
};

