const isCoarsePointer = window.matchMedia && window.matchMedia('(pointer: coarse)').matches;

const shapeSortConfig = {
  tileSizePx: isCoarsePointer ? 88 : 72,
  dragPaddingPx: isCoarsePointer ? 22 : 6,
  snapTolerancePx: isCoarsePointer ? 24 : 16,
};

.shape-sort-board {
  min-height: 360px;
  padding: 16px;
}

.shape-tile {
  width: 72px;
  height: 72px;
  border-radius: 18px;
}

@media (pointer: coarse) {
  .shape-sort-board {
    padding: 20px;
  }

  .shape-tile {
    width: 88px;
    height: 88px;
    border-radius: 22px;
  }
}

